import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String userInput = "../../../../../etc/passwd";
        String basePath = "/var/www/uploads/";
        String normalizedPath = Paths.get(basePath).normalize().toString();

        // Ensure that the userInput does not contain any directory traversal sequences
        if (!Paths.get(normalizedPath, userInput).normalize().startsWith(normalizedPath)) {
            System.out.println("Invalid path specified.");
            return;
        }

        String filePath = basePath + userInput;

        File file = new File(filePath);

        try {
            byte[] fileContent = Files.readAllBytes(file.toPath());
            System.out.println(new String(fileContent));
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }
}

